#[test]
fn test_count_json_files_mixed() {
    let tmp = tempdir().unwrap();
    let dir = tmp.path().join("mixed");
    std::fs::create_dir_all(&dir).unwrap();
    // 3 json files
    for i in 0..3 {
        std::fs::write(dir.join(format!("{i}.json")), "{}").unwrap();
    }
